from pathlib import Path
import re, collections
stop = set('the a an and or to of in is are be by for with when how what why who not only but all from into on under over after before this that these those as at it its their then than while because both can should do does did if through up out more most less very many much few own your our they we you i about against between around again still too'.split())
words=collections.Counter()
for p in list(Path('2 - Main Notes').glob('*.md'))+list(Path('3 - Indexes').glob('*.md'))+list(Path('Work').rglob('*.md')):
    text=p.read_text(errors='ignore')
    # prioritize titles and claim/vision headings perhaps first 1000 chars
    title=p.stem.lower()
    for w in re.findall(r"[A-Za-z][A-Za-z'-]+", title):
        if w not in stop and len(w)>2:
            words[w]+=2
    for m in re.finditer(r'^## Claim\n\n(.+?)(?:\n\n|$)', text, re.M|re.S):
        seg=m.group(1).lower()
        for w in re.findall(r"[A-Za-z][A-Za-z'-]+", seg):
            if w not in stop and len(w)>2:
                words[w]+=1
    for m in re.finditer(r'^## Vision\n\n(.+?)(?:\n\n|$)', text, re.M|re.S):
        seg=m.group(1).lower()
        for w in re.findall(r"[A-Za-z][A-Za-z'-]+", seg):
            if w not in stop and len(w)>2:
                words[w]+=1
print(words.most_common(80))
PY

